import{_ as i,r as l,o as r,c as d,b as a,e as h,w as p,d as t,f as c}from"./app-55c326ac.js";const n={},o=a("h1",{id:"chatgpt-提示工程框架",tabindex:"-1"},[a("a",{class:"header-anchor",href:"#chatgpt-提示工程框架","aria-hidden":"true"},"#"),t(" ChatGPT 提示工程框架")],-1),C={class:"table-of-contents"},P=c('<p>ChatGPT 是一种先进的人工智能模型，旨在理解和生成类似人类的文本。它可以发挥多种作用，包括充当招聘人员和采购人员的工具。然而，最大限度地发挥 ChatGPT 的优势可能具有挑战性，特别是对于那些不太精通技术或刚接触 AI 的人来说。</p><h2 id="一、简介" tabindex="-1"><a class="header-anchor" href="#一、简介" aria-hidden="true">#</a> 一、简介</h2><p>为了缓解这个问题，开发了一个名为 CRISPE 的框架。该框架提供了一个蓝图，用于为 ChatGPT 创建有效的提示，确保最佳利用率，无论您是在起草职位发布还是与潜在候选人进行沟通。</p><p>本文将深入研究 CRISPE 框架，阐明每个组件并展示其在各种招聘和人才采购场景中的应用。在本文结束时，您将了解如何利用 ChatGPT 作为招聘任务中的有效工具。</p><h2 id="二-crispe-框架解释" tabindex="-1"><a class="header-anchor" href="#二-crispe-框架解释" aria-hidden="true">#</a> 二. CRISPE 框架解释</h2><p>CRISPE 框架促进与 ChatGPT 的高效交互。 CRISPE 中的每个字母都代表有效提示的关键组成部分：</p><ul><li>能力和角色：此步骤需要定义您希望 ChatGPT 发挥作用的角色或能力。您使用 ChatGPT 作为文案吗？研究员？语言翻译？从一开始就清楚地概述这一点有助于指导人工智能的反应。</li><li>见解：这部分需要提供任何必要的背景或上下文信息。 ChatGPT 收到的相关详细信息越多，它的响应就越准确和恰当。</li><li>陈述：此元素是提示的核心：您要求 ChatGPT 做什么？您越具体，响应就越准确。</li><li>个性：您希望 ChatGPT 在其响应中给人留下怎样的印象？应该是正式、商务还是休闲、友好？该组件可以帮助您的交互增添个人风格。</li><li>实验：此组件鼓励您要求 ChatGPT 提供多个响应或示例，使您能够选择最好的一个或组合多个选项中的元素。</li></ul><p>CRISPE 框架并不是一个必须严格遵守的严格结构。将其视为一组有助于制定有效提示的指南。它提供了灵活性，允许您对其进行修改以满足您的特定需求。</p><h2 id="三-crispe框架在招聘中的应用" tabindex="-1"><a class="header-anchor" href="#三-crispe框架在招聘中的应用" aria-hidden="true">#</a> 三． CRISPE框架在招聘中的应用</h2><p>随着数字化转型的兴起，招聘经历了范式转变。从传统上在报纸上发布职位空缺并等待申请，招聘过程已经发展成为一个更加动态、多样化和技术驱动的领域。 ChatGPT 等人工智能 (AI) 工具凭借其理解和生成类人文本的能力，正在重塑招聘格局。这些工具有助于执行各种招聘任务。</p><p>CRISPE 框架是利用 ChatGPT 进行招聘的有效策略。它指导招聘人员和人才来源人员精心设计提示，从 ChatGPT 中提取最佳内容，从而帮助完成各种招聘任务。从制作引人注目的雇主品牌信息到制定候选人搜寻策略，CRISPE 框架可实现 ChatGPT 的有效使用。</p><p>然而，像 ChatGPT 这样的人工智能模型只有在有效使用时才能提供最佳结果。 CRISPE 框架不仅作为使用 ChatGPT 的工具，而且作为确保与 AI 进行富有成果和高效交互的重要指南。正确理解和应用该框架将使招聘人员和采购人员能够从 ChatGPT 中获得最大价值。</p><h2 id="四-案例研究-示例" tabindex="-1"><a class="header-anchor" href="#四-案例研究-示例" aria-hidden="true">#</a> 四．案例研究/示例</h2><h3 id="示例-1-使用-chatgpt-生成引人注目的雇主品牌内容" tabindex="-1"><a class="header-anchor" href="#示例-1-使用-chatgpt-生成引人注目的雇主品牌内容" aria-hidden="true">#</a> 示例 1：使用 ChatGPT 生成引人注目的雇主品牌内容</h3><p>您的雇主品牌可以极大地影响潜在候选人在招聘领域申请工作的决定。因此，如何展示公司文化、价值观和工作环境至关重要。借助 ChatGPT，您可以生成引人入胜且引人注目的内容，展示您的公司是一个有吸引力的工作场所。</p><p><img src="https://miro.medium.com/v2/resize:fit:1400/1*pTCzGe1XMErCpd5PP-biMw.png" alt=""></p><p><em>使用 CRISPE 框架，您可以创建提示，如下所示：</em></p><blockquote><p>能力和角色：内容撰稿人</p><p>洞察：我们公司是一家科技行业的初创公司，以其创新产品、包容性文化和对员工成长的承诺而闻名。</p><p>声明：撰写一篇 LinkedIn 帖子，重点介绍我们公司的优势并对潜在候选人有吸引力。</p><p>个性：专业，但友好和平易近人。</p><p>实验：提供帖子的三个不同版本。</p></blockquote><p>在这种情况下，CRISPE 框架的应用指导 ChatGPT 产生预期的结果 - 在这种情况下，吸引准确反映公司品牌的 LinkedIn 帖子。</p><h3 id="示例-2-利用-chatgpt-与潜在候选人进行沟通" tabindex="-1"><a class="header-anchor" href="#示例-2-利用-chatgpt-与潜在候选人进行沟通" aria-hidden="true">#</a> 示例 2：利用 ChatGPT 与潜在候选人进行沟通</h3><p>沟通是招聘不可或缺的一部分。无论是联系潜在候选人、回答询问，还是向申请人更新申请状态，有效的沟通都可以产生巨大的影响。为每位候选人起草个性化消息可能非常耗时，但 ChatGPT 可以提供帮助。</p><p><img src="https://miro.medium.com/v2/resize:fit:1400/1*sOi75GeIJrCuIKGGnpI4Eg.png" alt=""></p><p><em>使用 CRISPE 框架，我们可以要求 ChatGPT 向潜在候选人生成引人入胜的外展消息：</em></p><blockquote><p>能力和角色：沟通专家</p><p>洞察：候选人 John Doe 是我们在 LinkedIn {粘贴 Linkedin 个人资料}上找到的一位技术精湛的软件开发人员。我们有一个职位空缺{粘贴职位添加}，与他的技能和经验完美匹配。</p><p>声明：给 John Doe 写一封外展信息，邀请他考虑该职位空缺。</p><p>个性：专业、礼貌、个性化。</p><p>实验：生成消息的两个不同版本。</p></blockquote><p>ChatGPT 的使用使招聘人员无需花费过多的时间和精力即可保持高质量的沟通。</p><h3 id="示例3-使用chatgpt进行谈判训练" tabindex="-1"><a class="header-anchor" href="#示例3-使用chatgpt进行谈判训练" aria-hidden="true">#</a> 示例3：使用ChatGPT进行谈判训练</h3><p>谈判工作机会是招聘中的一项关键技能。这不仅仅是说服候选人接受这份工作，还要达成符合公司预算和政策的协议。练习谈判场景可以提高招聘人员的技能，而 ChatGPT 可以在这方面提供帮助。</p><p><img src="https://miro.medium.com/v2/resize:fit:1400/1*mpO1V30I0z3TpUmRJmyQ4w.png" alt=""></p><p><em>以下是我们如何使用 CRISPE 框架创建谈判场景：</em></p><blockquote><p>能力和角色：培训合作伙伴</p><p>洞察：我们正在模拟与一位拥有另一份工作机会的高级候选人的谈判。我们公司不能超出预算，但我们可以提供其他福利，例如灵活的工作时间、股票期权和专业发展机会。</p><p>陈述：模拟一场谈判对话，候选人试图谈判比我们能提供的更高的薪水，我们必须用其他好处说服他们。</p><p>性格：专业、自信，但也善解人意、体贴。</p><p>实验：生成两个不同版本的对话。</p></blockquote><p>ChatGPT 的这种使用可以提供一个现实的练习平台，帮助招聘人员提高谈判技巧。</p><h3 id="示例-4-使用-chatgpt-生成候选人采购策略的想法" tabindex="-1"><a class="header-anchor" href="#示例-4-使用-chatgpt-生成候选人采购策略的想法" aria-hidden="true">#</a> 示例 4：使用 ChatGPT 生成候选人采购策略的想法</h3><p>寻找高质量的候选人往往是招聘中最大的挑战之一。它需要战略方法、创造力以及对就业市场的深入了解。这是另一项使用 ChatGPT 可以变得更容易的任务。</p><p><img src="https://miro.medium.com/v2/resize:fit:1400/1*B39R_U8kYTLGKd0cu7AGGw.png" alt=""></p><p><em>使用 CRISPE 框架，我们可以集思广益采购策略：</em></p><blockquote><p>能力和角色：创意产生者</p><p>洞察力：我们正在寻找高技能的数据科学家，但我们正在努力寻找足够的合格候选人。我们使用了招聘网站和 LinkedIn 等传统方法，但我们需要扩展我们的方法。</p><p>声明：集思广益寻找数据科学家的创新策略。</p><p>个性：富有创意且细致。</p><p>实验：提供五种不同的策略。</p></blockquote><p>通过以这种方式应用 CRISPE 框架，您可以挖掘 ChatGPT 的创造潜力并提出新策略，从而有可能发现未开发的人才来源。</p><h2 id="五、使用crispe框架进行招聘的优势" tabindex="-1"><a class="header-anchor" href="#五、使用crispe框架进行招聘的优势" aria-hidden="true">#</a> 五、使用CRISPE框架进行招聘的优势</h2><p>人工智能在招聘和人才招聘中的应用带来了许多优势，从提高效率到支持更好的决策。 CRISPE 框架通过优化 ChatGPT 在招聘任务中的使用来增强这些优势。以下是该框架的一些显着优点：</p><ol><li>效率和生产力：CRISPE 框架通过指导您制作有效的提示，帮助您在第一次尝试时从 ChatGPT 获得所需的输出，从而减少迭代和改写所花费的时间。</li><li>精确性和相关性：该框架鼓励提供详细的说明和上下文，从而使 ChatGPT 的响应更加精确且更符合您的需求。</li><li>多功能性：CRISPE 框架不限于特定任务或场景。无论您是在寻找候选人、制作品牌内容还是进行谈判培训，您都可以使用此框架来指导与 ChatGPT 的交互。</li><li>改善沟通：通过定义 ChatGPT 响应的个性，您可以定制 AI 的沟通风格，以匹配您公司的语气或具体情况，从而提高与候选人和利益相关者的互动。</li><li>创造性地解决问题：CRISPE 框架的实验部分可以使 ChatGPT 提供多种解决方案或建议，让您探索解决问题或任务的不同方法。</li></ol><p>从本质上讲，CRISPE 框架是增强您与 ChatGPT 交互的工具，确保该 AI 模型成为您招聘和人才搜寻工作中的宝贵资产。</p><h2 id="结论" tabindex="-1"><a class="header-anchor" href="#结论" aria-hidden="true">#</a> 结论</h2><p>人工智能在招聘领域的兴起不仅仅是一种趋势，更是一种趋势。这是向更智能、更高效的实践的有意义的转变。正如我们所看到的，ChatGPT 是一个强大的工具，可以支持招聘的各个方面，从采购和沟通到雇主品牌和谈判培训。但为了充分发挥其潜力，像 CRISPE 框架这样的结构化方法是必要的。</p><p>CRISPE 框架指导招聘人员和采购人员为 ChatGPT 制作有效的提示，确保人工智能的响应满足他们的需求和期望。无论您是一位精通技术、希望优化 AI 使用的招聘人员，还是刚刚开始 AI 之旅的新手，CRISPE 框架都可以帮助您充分利用 ChatGPT。</p>',44);function s(u,G){const e=l("router-link");return r(),d("div",null,[o,a("nav",C,[a("ul",null,[a("li",null,[h(e,{to:"#一、简介"},{default:p(()=>[t("一、简介")]),_:1})]),a("li",null,[h(e,{to:"#二-crispe-框架解释"},{default:p(()=>[t("二. CRISPE 框架解释")]),_:1})]),a("li",null,[h(e,{to:"#三-crispe框架在招聘中的应用"},{default:p(()=>[t("三． CRISPE框架在招聘中的应用")]),_:1})]),a("li",null,[h(e,{to:"#四-案例研究-示例"},{default:p(()=>[t("四．案例研究/示例")]),_:1}),a("ul",null,[a("li",null,[h(e,{to:"#示例-1-使用-chatgpt-生成引人注目的雇主品牌内容"},{default:p(()=>[t("示例 1：使用 ChatGPT 生成引人注目的雇主品牌内容")]),_:1})]),a("li",null,[h(e,{to:"#示例-2-利用-chatgpt-与潜在候选人进行沟通"},{default:p(()=>[t("示例 2：利用 ChatGPT 与潜在候选人进行沟通")]),_:1})]),a("li",null,[h(e,{to:"#示例3-使用chatgpt进行谈判训练"},{default:p(()=>[t("示例3：使用ChatGPT进行谈判训练")]),_:1})]),a("li",null,[h(e,{to:"#示例-4-使用-chatgpt-生成候选人采购策略的想法"},{default:p(()=>[t("示例 4：使用 ChatGPT 生成候选人采购策略的想法")]),_:1})])])]),a("li",null,[h(e,{to:"#五、使用crispe框架进行招聘的优势"},{default:p(()=>[t("五、使用CRISPE框架进行招聘的优势")]),_:1})]),a("li",null,[h(e,{to:"#结论"},{default:p(()=>[t("结论")]),_:1})])])]),P])}const I=i(n,[["render",s],["__file","ChatGPT 提示工程框架.html.vue"]]);export{I as default};
